const REGISTRY = [
  { id: 'copilot-chat', name: 'VS Code Copilot Chat', agent: 'GitHub Copilot', priority: 100, fingerprint: [{ path: 'responderUsername', check: 'type_string' }, { path: 'requests', check: 'type_array' }, { path: 'requests[0].message', check: 'type_object' }, { path: 'requests[0].variableData', check: 'type_object' }] },
];
function getByPath(obj, path) { if (!obj || !path) return undefined; return path.replace(/\[(\d+)\]/g, '.$1').split('.').reduce((o, k) => o != null ? o[k] : undefined, obj); }
function evaluateRule(data, rule) { const v = getByPath(data, rule.path); switch (rule.check) { case 'type_string': return typeof v === 'string'; case 'type_array': return Array.isArray(v); case 'type_object': return typeof v === 'object' && v !== null && !Array.isArray(v); case 'exists': return v != null; case 'equals': return v === rule.value; case 'matches': return typeof v === 'string' && typeof rule.value === 'string' && new RegExp(rule.value).test(v); case 'has_key': return typeof v === 'object' && v !== null && typeof rule.value === 'string' && rule.value in v; default: return false; } }
function detectFormat(data) {
  let bestPartial = null;
  for (const fmt of [...REGISTRY].sort((a, b) => b.priority - a.priority)) {
    const results = fmt.fingerprint.map(r => ({ rule: r, passed: evaluateRule(data, r) }));
    if (results.every(r => r.passed)) return { matched: true, formatId: fmt.id, format: fmt, confidence: 'exact' };
    const passedCount = results.filter(r => r.passed).length;
    if (passedCount > 0 && (!bestPartial || passedCount > bestPartial.passedCount)) bestPartial = { formatId: fmt.id, passedCount, total: results.length };
  }
  const topLevel = Object.fromEntries(Object.keys(data || {}).map(k => [k, Array.isArray(data[k]) ? 'array[' + data[k].length + ']' : typeof data[k]]));
  return { matched: false, formatId: null, confidence: bestPartial ? 'partial' : 'none', diagnostic: JSON.stringify(topLevel), bestPartial };
}
const body = $input.first().json.body || $input.first().json;
const projectName = body.projectName || 'chat-traces';
const sourceLabel = body.sourceLabel || body.filename || 'unknown';
const chatData = body.chatData || body;
const detection = detectFormat(chatData);
if (!detection.matched) {
  return [{ json: { detected: false, error: 'Unknown chat format', confidence: detection.confidence, diagnostic: detection.diagnostic, bestPartial: detection.bestPartial, _rawData: chatData, _sourceLabel: sourceLabel } }];
}
return [{ json: { detected: true, formatId: detection.formatId, format: detection.format, chatData, projectName } }];

const { formatId, chatData, projectName } = $input.first().json;
function getByPath(obj, path) { if (!obj || !path) return undefined; return path.replace(/\[(\d+)\]/g, '.$1').split('.').reduce((o, k) => o != null ? o[k] : undefined, obj); }
function assembleCopilotResponse(responses) { if (!Array.isArray(responses)) return ''; const parts = []; for (const r of responses) { const kind = r?.kind; if (['thinking','mcpServersStarting','undoStop','confirmation'].includes(kind)) continue; if (kind === 'toolInvocationSerialized') { const msg = r.pastTenseMessage || r.invocationMessage || ''; const text = typeof msg === 'object' ? (msg.value || '') : String(msg); if (text) parts.push('[Tool] ' + text); continue; } if (kind === 'progressTaskSerialized' && r.content?.value) { parts.push(r.content.value); continue; } if (typeof r?.value === 'string' && r.value.trim()) parts.push(r.value); } return parts.join('\n'); }
function extractCopilotThinking(turn) { const resp = turn.response; if (!Array.isArray(resp)) return ''; return resp.filter(r => r?.kind === 'thinking' && r?.value).map(r => r.value).join('\n---\n'); }
function extractCopilotToolCalls(turn) { const rounds = getByPath(turn, 'result.metadata.toolCallRounds'); if (!Array.isArray(rounds)) return []; const calls = []; for (let ri = 0; ri < rounds.length; ri++) { for (const tc of (rounds[ri]?.toolCalls || [])) { calls.push({ name: tc.name || 'unknown', input: (typeof tc.arguments === 'string' ? tc.arguments : JSON.stringify(tc.arguments || '')).slice(0, 2000), output: (typeof tc.result === 'string' ? tc.result : '').slice(0, 2000), round: ri }); } } return calls; }
function normalizeCopilot(data, projName) { const turns = data.requests || []; const normalized = []; for (let i = 0; i < turns.length; i++) { const t = turns[i]; const userMsg = getByPath(t, 'message.text') || ''; if (!userMsg.trim()) continue; normalized.push({ index: i, userMessage: userMsg, assistantResponse: assembleCopilotResponse(t.response), model: t.modelId || 'unknown', timestampMs: t.timestamp || null, latencyMs: getByPath(t, 'result.timings.totalElapsed') || null, tokens: { prompt: getByPath(t, 'result.metadata.promptTokens') || 0, completion: getByPath(t, 'result.metadata.outputTokens') || 0 }, toolCalls: extractCopilotToolCalls(t), thinking: extractCopilotThinking(t) || undefined, metadata: {} }); } return { format: 'copilot-chat', agent: 'GitHub Copilot', projectName: projName, sessionId: getByPath(turns[0], 'result.metadata.sessionId') || '', responder: data.responderUsername || 'unknown', turns: normalized }; }
let payload; switch (formatId) { case 'copilot-chat': payload = normalizeCopilot(chatData, projectName); break; default: return [{ json: { error: 'No normalizer for ' + formatId } }]; }
if (!payload.turns?.length) return [{ json: { error: 'No turns extracted' } }];
return [{ json: { payload, stats: { format: formatId, turnsExtracted: payload.turns.length, toolCallsFound: payload.turns.reduce((s, t) => s + (t.toolCalls?.length || 0), 0) } } }];

// DISCOVERY STEP - sample unknown format for offline analysis
const detection = $input.first().json;
const chatData = detection._rawData || {};
const sourceLabel = detection._sourceLabel || 'unknown';

function describeType(v) {
  if (v === null) return 'null';
  if (v === undefined) return 'undefined';
  if (Array.isArray(v)) return v.length === 0 ? 'array[0]' : 'array[' + v.length + ']<' + describeType(v[0]) + '>';
  if (typeof v === 'object') { const k = Object.keys(v); return k.length <= 5 ? 'object{' + k.join(',') + '}' : 'object{' + k.slice(0,5).join(',') + ',...+' + (k.length-5) + '}'; }
  if (typeof v === 'string') return v.length > 50 ? 'string(' + v.length + 'chars)' : 'string';
  return typeof v;
}

function truncate(obj, max) {
  max = max || 200;
  if (obj===null||obj===undefined) return obj;
  if (typeof obj==='string') return obj.slice(0,max);
  if (typeof obj==='number'||typeof obj==='boolean') return obj;
  if (Array.isArray(obj)) return obj.slice(0,3).map(function(i){return truncate(i,max);});
  if (typeof obj==='object') { var r={}; for (var ek of Object.keys(obj)) r[ek]=truncate(obj[ek],max); return r; }
  return obj;
}

function mapKeys(obj, pfx, depth, max) {
  pfx = pfx || ''; depth = depth || 0; max = max || 5;
  if (depth>=max||!obj||typeof obj!=='object') return [];
  var entries=[];
  var keys=Array.isArray(obj)?['[0]']:Object.keys(obj);
  var tgt=Array.isArray(obj)?{'[0]':obj[0]}:obj;
  for (var k of keys) {
    var fp=pfx?(pfx+'.'+k):k; var v=tgt[k];
    var e={path:fp,type:describeType(v)};
    if (typeof v==='string'&&v.length>0) e.sample=v.slice(0,100);
    entries.push(e);
    if (typeof v==='object'&&v!==null&&!Array.isArray(v)) entries=entries.concat(mapKeys(v,fp,depth+1,max));
    else if (Array.isArray(v)&&v.length>0) entries=entries.concat(mapKeys(v[0],fp+'[0]',depth+1,max));
  }
  return entries;
}

var chatMarkers=['message','content','text','role','response','request','prompt'];
var turnsNames=['messages','requests','turns','conversation','exchanges','chat'];
var candidatePath=null, candidateCount=0, bestScore=0;
for (var [key,value] of Object.entries(chatData)) {
  if (!Array.isArray(value)||value.length===0) continue;
  if (typeof value[0]!=='object'||value[0]===null) continue;
  var fk=Object.keys(value[0]).map(function(k){return k.toLowerCase();});
  var score=value.length;
  for (var m of chatMarkers) if (fk.some(function(k){return k.includes(m);})) score+=100;
  if (turnsNames.includes(key.toLowerCase())) score+=200;
  if (score>bestScore) { bestScore=score; candidatePath=key; candidateCount=value.length; }
}

var topSchema={};
for (var [tk,tv] of Object.entries(chatData)) topSchema[tk]=describeType(tv);
var firstTurnSchema=null, firstTurnSample=null;
if (candidatePath&&Array.isArray(chatData[candidatePath])&&chatData[candidatePath].length>0) {
  var ft=chatData[candidatePath][0]; firstTurnSchema={};
  for (var [fk2,fv2] of Object.entries(ft)) firstTurnSchema[fk2]=describeType(fv2);
  firstTurnSample=truncate(ft,200);
}

var deepKeyMap=mapKeys(chatData,'',0,5);
var sig=Object.keys(chatData).sort().map(function(k){var v=chatData[k];return Array.isArray(v)?(k+':arr'+v.length):(k+':'+typeof v);}).join('|');
var hash=0; for(var i=0;i<sig.length;i++){hash=((hash<<5)-hash)+sig.charCodeAt(i);hash|=0;}
var contentHash=Math.abs(hash).toString(36).padStart(8,'0');
var now=new Date();
var datePart=now.toISOString().replace(/[:.]/g,'-').slice(0,19);

return [{json:{
  sampled:true,
  suggestedFilename:'unknown-'+sourceLabel+'-'+datePart+'-'+contentHash.slice(0,6)+'.json',
  sample:{sampledAt:now.toISOString(),contentHash:contentHash,sourceLabel:sourceLabel,topLevelSchema:topSchema,firstTurnSchema:firstTurnSchema,candidateTurnsPath:candidatePath,candidateTurnsCount:candidateCount,diagnosticText:detection.diagnostic||'',firstTurnSample:firstTurnSample,deepKeyMap:deepKeyMap},
  detection:{matched:false,confidence:detection.confidence||'none',formatId:null}
}}];
